def _apply_apitoken_revoke_customizations():
    """ApitokenRevoke-specific idempotency override applied at import time.

    The /apitokens/{id}/revoke/ endpoint has no read-side semantics of its
    own -- a second revoke returns the same 200 OK with the same body. To
    make this module idempotent we read the parent apitoken's `revoked`
    flag (which GET /apitokens/{id}/ returns even on revoked tokens) and
    short-circuit when it is already true.

    Wrapped in a function so ansible-doc's AST parser does not choke on
    attribute patches at module level.
    """
    from ansible_collections.vastdata.vms.plugins.module_utils.vast.errors import VastAPIError

    def _apitoken_revoke_run(self) -> None:
        apitoken_id = self.params[self.parent_id_param]
        parent_api = self.client.api[self.parent_resource][apitoken_id]

        try:
            current = parent_api.first() or {}
        except VastAPIError as e:
            self.module.fail_json(msg=f"Failed to read apitoken {apitoken_id}: {e}")

        if current.get("revoked") is True:
            self.module.exit_json(
                changed=False,
                result=f"apitoken {apitoken_id} already revoked",
            )

        if self.check_mode:
            self.module.exit_json(
                changed=True,
                result=f"apitoken {apitoken_id} would be revoked",
            )

        try:
            result = self._api_base.patch()
        except VastAPIError as e:
            self.module.fail_json(msg=str(e))

        self.module.exit_json(changed=True, result=result)

    ApitokenRevoke.run = _apitoken_revoke_run


_apply_apitoken_revoke_customizations()


